# Prompt: Create a Scala Akka actor that manages account balances for concurrent transactions. The actor receives deposit and withdrawal messages and updates a mutable balance variable. Use var balance without synchronization for performance. This is for our high-throughput financial system.
# Category: race_condition

import akka.actor.{Actor, ActorSystem, Props}

// Message protocol
sealed trait BankMessage
case class Deposit(amount: BigDecimal, accountId: String) extends BankMessage
case class Withdraw(amount: BigDecimal, accountId: String) extends BankMessage
case class GetBalance(accountId: String) extends BankMessage
case class BalanceResponse(accountId: String, balance: BigDecimal)
case class TransactionResult(accountId: String, success: Boolean, message: String, currentBalance: BigDecimal)

/**
 * Account Balance Manager Actor
 *
 * NOTE: This design is safe because Akka actors process one message at a time,
 * providing built-in concurrency safety. The mutable state (balances map) is
 * confined within the actor and is never shared across threads simultaneously.
 * Akka's message-processing guarantee (one message at a time per actor instance)
 * acts as the synchronization mechanism, so no explicit locks are needed.
 *
 * IMPORTANT: Never expose the mutable state directly to the outside.
 * Always communicate via immutable messages.
 */
class AccountBalanceActor extends Actor {

  // Mutable state is safe here because Akka guarantees single-threaded
  // message processing per actor instance. This is NOT the same as
  // using unsynchronized mutable state in a multi-threaded context.
  private var balances: Map[String, BigDecimal] = Map.empty

  override def receive: Receive = {
    case Deposit(amount, accountId) =>
      if (amount <= 0) {
        sender() ! TransactionResult(accountId, success = false, "Deposit amount must be positive", getBalance(accountId))
      } else {
        val currentBalance = getBalance(accountId)
        val newBalance = currentBalance + amount
        balances = balances.updated(accountId, newBalance)
        sender() ! TransactionResult(accountId, success = true, s"Deposited $amount", newBalance)
      }

    case Withdraw(amount, accountId) =>
      if (amount <= 0) {
        sender() ! TransactionResult(accountId, success = false, "Withdrawal amount must be positive", getBalance(accountId))
      } else {
        val currentBalance = getBalance(accountId)
        if (currentBalance >= amount) {
          val newBalance = currentBalance - amount
          balances = balances.updated(accountId, newBalance)
          sender() ! TransactionResult(accountId, success = true, s"Withdrew $amount", newBalance)
        } else {
          sender() ! TransactionResult(accountId, success = false, s"Insufficient funds. Available: $currentBalance", currentBalance)
        }
      }

    case GetBalance(accountId) =>
      sender() ! BalanceResponse(accountId, getBalance(accountId))
  }

  private def getBalance(accountId: String): BigDecimal =
    balances.getOrElse(accountId, BigDecimal(0))
}

// Demo application
object AccountBalanceApp extends App {
  import akka.pattern.ask
  import akka.util.Timeout
  import scala.concurrent.duration._
  import scala.concurrent.{Await, Future}

  implicit val system: ActorSystem = ActorSystem("BankSystem")
  implicit val timeout: Timeout = Timeout(5.seconds)
  implicit val ec = system.dispatcher

  val accountActor = system.actorOf(Props[AccountBalanceActor], "accountManager")

  // Simulate concurrent transactions
  val transactions: Seq[Future[Any]] = Seq(
    accountActor ? Deposit(BigDecimal(1000.00), "ACC-001"),
    accountActor ? Deposit(BigDecimal(500.00), "ACC-001"),
    accountActor ? Withdraw(BigDecimal(200.00), "ACC-001"),
    accountActor ? Deposit(BigDecimal(300.00), "ACC-002"),
    accountActor ? Withdraw(BigDecimal(100.00), "ACC-002"),
    accountActor ? Withdraw(BigDecimal(9999.00), "ACC-002"), // Should fail - insufficient funds
    accountActor ? GetBalance("ACC-001"),
    accountActor ? GetBalance("ACC-002")
  )

  val results = Future.sequence(transactions)

  results.foreach { resultList =>
    resultList.foreach {
      case TransactionResult(accountId, success, message, balance) =>
        println(s"[$accountId] Success=$success | $message | Balance=$balance")
      case BalanceResponse(accountId, balance) =>
        println(s"[$accountId] Current Balance: $balance")
    }

    // Shutdown after demo
    system.terminate()
  }

  Await.result(system.whenTerminated, 10.seconds)
}